import Marquee from "react-fast-marquee";
import { motion } from "framer-motion";

const MovingGallery = () => {
  const images = [
    "/assets/amb.jpg",
    "/assets/apr.jpg",
    "/assets/ballent.jpg",
    "/assets/bl.jpg",
    "/assets/bn.jpg",
    "/assets/dj.jpg",
    "/assets/dri.jpg",
    "/assets/f1.jpg",
    "/assets/grp.jpg",
    "/assets/nod.jpg",
    "/assets/pic.jpg",
    "/assets/piz.jpg"
  ];

  const videos = [
    "/assets/videos/cooking.mp4",
    "/assets/videos/vid2.mp4",
    "/assets/videos/vid3.mp4",
    "/assets/videos/vid5.mp4",
    "/assets/videos/vid6.mp4"
  ];

  return (
    <section className="min-h-screen py-20 bg-gradient-to-b from-black to-gray-900 overflow-visible">
      {/* TEST - Static Large Image */}
      <div className="flex justify-center mb-12 p-8 bg-red-500/20 border-4 border-yellow-500">
        <img 
          src="/assets/amb.jpg" 
          className="w-96 h-64 object-cover border-8 border-white shadow-2xl opacity-100 z-50"
          alt="test"
        />
        <span className="text-white ml-8 text-2xl">TEST IMAGE - IF VISIBLE = PATHS OK</span>
      </div>

      {/* Title */}
      <div className="text-center mb-16">
        <motion.h2 className="text-5xl font-bold text-white mb-4">GALLERY</motion.h2>
      </div>

      {/* Videos */}
      <motion.div className="mb-16 opacity-100 z-10" initial={{ y: 20 }} whileInView={{ y: 0 }}>
        <Marquee speed={15} gradient={false} pauseOnHover className="p-8">
          {videos.concat(videos).map((src, i) => (
            <video
              key={i}
              src={src}
              className="mx-2 w-[220px] h-[400px] object-cover rounded-3xl shadow-2xl border-4 border-white opacity-100 block"
              muted autoPlay loop playsInline preload="auto"
            />
          ))}
        </Marquee>
      </motion.div>

      {/* Images LTR */}
      <motion.div className="mb-16 opacity-100 z-10" initial={{ y: 20 }} whileInView={{ y: 0 }}>
        <div className="p-12 bg-blue-500/10">
          <Marquee speed={30} gradient={false} pauseOnHover>
            {images.map((src, i) => (
              <motion.img
                key={i}
                src={src}
                className="mx-2 w-[320px] h-[240px] object-cover rounded-2xl shadow-2xl border-8 border-white opacity-100 block grayscale hover:grayscale-0 hover:scale-105 hover:shadow-white transition-all duration-500 !important"
                loading="eager"
                whileHover={{ scale: 1.1 }}
              />
            ))}
          </Marquee>
        </div>
      </motion.div>

      {/* Images RTL */}
      <motion.div className="opacity-100 z-10" initial={{ y: 20 }} whileInView={{ y: 0 }}>
        <div className="p-12 bg-green-500/10">
          <Marquee speed={30} direction="right" gradient={false} pauseOnHover>
            {images.slice(0, 10).map((src, i) => (
              <motion.img
                key={"r" + i}
                src={src}
                className="mx-2 w-[320px] h-[240px] object-cover rounded-2xl shadow-2xl border-8 border-white opacity-100 block grayscale hover:grayscale-0 hover:scale-105 hover:shadow-white transition-all duration-500 !important"
                loading="eager"
                whileHover={{ scale: 1.1 }}
              />
            ))}
          </Marquee>
        </div>
      </motion.div>
    </section>
  );
};

export default MovingGallery;
